def assess(record: dict) -> str:
    required = {'case_id', 'seed', 'params', 'metric', 'rerun_metric', 'tolerance'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (abs(record["metric"] - record["rerun_metric"]) > record["tolerance"])) else "MARK_RUN_NONREPRODUCIBLE"

valid = {'case_id': 'CASO-TAC-047-1A', 'seed': 42, 'params': {'depth': 4}, 'metric': 0.81, 'rerun_metric': 0.805, 'tolerance': 0.01}
invalid = {'case_id': 'CASO-TAC-047-1A', 'seed': 42, 'params': {'depth': 4}, 'metric': 1000000.81, 'rerun_metric': 0.805, 'tolerance': 0.01}
incomplete = {**valid}
incomplete.pop("tolerance", None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

